script:
frappe.ui.form.on("Hostel leaves", {
    student: function(frm) {
        if (!frm.doc.student) return;

        frappe.db.get_list("Hostel Admission", {
            filters: { student: frm.doc.student, admission_status: "Checked In" },
            fields: ["name", "hostel", "hostel_block", "hostel_room"],
            limit: 1
        }).then(records => {
            if (!records.length) {
                frappe.msgprint("No active (Checked In) admission found for this student.");
                return;
            }
            let a = records[0];
            frm.set_value("hostel_admission", a.name);
            frm.set_value("hostel", a.hostel);
            frm.set_value("hostel_block", a.hostel_block);
            frm.set_value("hostel_room", a.hostel_room);
        });

        frappe.db.get_value("Custom Student", frm.doc.student, "guardian_mobile")
            .then(({message}) => {
                if (message && message.guardian_mobile) {
                    frm.set_value("parent_contact", message.guardian_mobile);
                }
            });
    },

    refresh(frm) {
        if (frm.is_new()) return;

        if (frm.doc.approval_status === "Approved" && !frm.doc.actual_return_date) {
            frm.add_custom_button("Mark Returned", function() {
                frappe.confirm(
                    `Mark ${frm.doc.student} as returned now?`,
                    () => {
                        frm.set_value("actual_return_date", frappe.datetime.get_today());
                        frm.set_value("actual_return_time", frappe.datetime.now_time());
                        frm.save();
                    }
                );
            }).addClass("btn-primary");
        }

        if (frm.doc.gate_pass_number) {
            frm.dashboard.add_indicator(`Gate Pass: ${frm.doc.gate_pass_number}`, "blue");
        }
    }
});
